solution_code:
#include <iostream>
#include <limits>

int main() {
    int n = 0;
    while (true) {
        std::cin >> n;
        if (!std::cin) {
            std::cin.clear();
            std::cin.ignore(std::numeric_limits<std::streamsize>::max(), '\n');
        } else if (n > 0) {
            break;
        }
    }
    std::cout << "Valid: " << n << "\n";
    return 0;
}
